from flask import Flask, request, jsonify
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='application.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

@app.route('/login', methods=['POST'])
def login():
    username = request.json['username']
    password = request.json['password']
    email = request.json['email']

    # Perform authentication logic here
    # ...

    # Log login attempt
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent')
    logging.info(f"Login attempt: username={username}, password={password}, email={email}, ip_address={ip_address}, user_agent={user_agent}")

    # Return JSON response
    return jsonify({'message': 'Login successful'})

if __name__ == '__main__':
    app.run(debug=True)